#!/bin/sh
# AgentVault layer-2 scrub hook (generated by `av init --agent claude-code`).
#
# Pipes this hook's stdin through `av scrub`, which forwards to the AgentVault daemon
# for redaction: session values (exact-match + encodings) and gitleaks-detected
# secrets are replaced with {{AV:NAME}} / {{AV:REDACTED:<rule>}} before the text
# reaches the agent's context.
#
# Wire this on EVERY context-ingress channel (see .claude/agentvault.hooks.json and
# .claude/skills/agentvault/SKILL.md). A channel left unhooked is a hole.
exec av scrub
